// // This module extends a 16-bit input to 32 bits based on a 2-bit control signal EXTop.
// If EXTop is 'b00', it prepends 16 ones to the left of imm16;
// If EXTop is 'b01', it places imm16 in the most significant 16 bits and pads the lower 16 bits with ones;
// If EXTop is 'b10', it sign-extends imm16 by replicating the least significant bit to fill the lower 16 bits;
// For any other value of EXTop, it outputs a fixed 32-bit value of 32'b1111111111111111.
module top_module( EXTop,imm16,extout);input [15:0]  imm16;
    input [1:0]   EXTop;
    output [31:0] extout;

    assign extout = (EXTop == 'b00) ? { imm16,16'b0}:
                      (EXTop == 'b01) ? { 16'b0,imm16}:
                      (EXTop == 'b10) ? { {16{imm16[15]}},imm16}:
                      32'b0001001000110100;
endmodule

